import{d as F,r as u,h as N,G as V,a as p,o as c,v as R,w as _,F as q,s as O,k as $,q as S,f as L,n as k,b as n,e as h,t as x,C as D,H as J,I as U}from"./main-MIdDc-9O.js";import{S as j,b as G,K,A as P,a as Q}from"./autoplay-ClUc7fUG.js";import{_ as X}from"./_plugin-vue_export-helper-DlAUqK2U.js";const Y={class:"relative -mx-4 sm:-mx-6 md:-mx-8 mb-0"},Z={class:"mb-4 flex items-center justify-between"},ee={key:0,class:"expand-indicator","aria-label":"Развернуть"},te={class:"text-base leading-snug opacity-95"},ae={class:"card-overlay-header"},ne={key:0,class:"card-overlay-title"},se={class:"card-overlay-body"},le={key:1,class:"card-overlay-source"},re=8,ie=F({__name:"FactsCarouselV2",setup(oe){const I=[G,K,P],z={delay:5e3,disableOnInteraction:!1,pauseOnMouseEnter:!1,stopOnLastSlide:!1,reverseDirection:!1},m=u([]),b=u(224),i=u(null),f=u(Math.round(window.innerWidth*.86)),w=u(Math.max(0,Math.round((window.innerWidth-f.value)/2))),s=u(null),H=e=>{var a,t,l,r,o,y,E;s.value=e,window.triggerHaptic&&window.triggerHaptic("light"),(t=(a=i.value)==null?void 0:a.autoplay)==null||t.stop();try{const d=(l=window==null?void 0:window.Telegram)==null?void 0:l.WebApp;(o=(r=d==null?void 0:d.BackButton)==null?void 0:r.show)==null||o.call(r),(E=(y=d==null?void 0:d.BackButton)==null?void 0:y.onClick)==null||E.call(y,()=>g())}catch{}},g=()=>{var e,a,t,l,r;s.value=null,(a=(e=i.value)==null?void 0:e.autoplay)==null||a.start();try{const o=(t=window==null?void 0:window.Telegram)==null?void 0:t.WebApp;(r=(l=o==null?void 0:o.BackButton)==null?void 0:l.hide)==null||r.call(l)}catch{}},C=e=>e==="Факт"?"fact":e==="Символ"?"symbol":e==="Миф"?"myth":"fact",T=e=>e==="Факт"?"🔬 Факт":e==="Символ"?"🌀 Символ":e==="Миф"?"💭 Миф":e,W=u([{id:1,type:"Факт",text:"Большинство снов забываются в течение первых 5-10 минут после пробуждения.",expandable:!0,title:"Почему мы забываем сны?",fullText:`Забывание снов — это не случайность, а биологический механизм. Во время REM-сна гиппокамп — область мозга, ответственная за перенос воспоминаний — работает иначе, чем при бодрствовании. Нейромедиатор норэпинефрин, необходимый для формирования долгосрочных воспоминаний, почти не вырабатывается в этой фазе.

Первые 5–10 минут после пробуждения — критическое окно. Если сразу взяться за телефон или поговорить, образы сна вытесняются. Исследования показывают, что те, кто ведёт дневник снов, начинают помнить их значительно лучше уже через 2–3 недели практики.

Эффективный способ запомнить сон — не двигаться сразу после пробуждения, остаться в той же позе и мысленно "прокрутить" образы. Только после этого записать. Мозг буквально переобучается фиксировать сновидения.`,source:'Hobson & McCarley, "The Brain as a Dream State Generator" (1977)'},{id:2,type:"Символ",text:"Полет во сне — ощущение свободы или побег от проблем.",expandable:!0,title:"Полёт во сне",fullText:"Полёт во сне — один из самых распространённых сюжетов. Юнгианская психология связывает его с желанием выйти за пределы обыденного и обрести контроль над жизнью. Часто такие сны случаются в периоды больших перемен или стресса. Если полёт лёгкий — это признак уверенности в себе. Если трудный или страшный — возможно, вы чувствуете себя перегруженным.",source:'Jung, "Man and His Symbols" (1964)'},{id:3,type:"Факт",text:"Слепые от рождения люди видят сны, используя другие чувства: слух, обоняние, осязание.",expandable:!0,title:"Сны без зрения",fullText:`Для людей, слепых от рождения, сновидения — это богатый мультисенсорный опыт, в котором зрительные образы просто отсутствуют. Вместо них — звуки, тактильные ощущения, запахи и эмоции. Исследование 2014 года (Meaidi et al.) показало, что сны незрячих от рождения так же эмоционально насыщены, как и зрячих, и так же часто включают кошмары.

Интересно: у людей, потерявших зрение после рождения, зрительные образы сохраняются в снах. Те, кто ослеп в детстве до 5–7 лет, со временем теряют визуальные сны. После 7 лет — образы остаются на всю жизнь.

Это открытие подтверждает, что мозг при построении снов использует весь доступный сенсорный опыт — и адаптируется под него. Сновидение — это не картинка, а реконструкция всего накопленного опыта.`,source:"Meaidi et al., Sleep Medicine (2014)"},{id:4,type:"Миф",text:"Миф: люди снятся только черно-белыми. На самом деле 80% людей видят цветные сны.",expandable:!0,title:"Цвет снов",fullText:"Исследования 1940-х годов показывали, что большинство снов черно-белые — но в то время чёрно-белое телевидение было нормой. Современные исследования с использованием фМРТ показывают, что мозг активирует цветовые зоны зрительной коры во время REM-сна. Около 80% людей сегодня видят цветные сны. Те, кто вырос с ч/б ТВ, действительно чаще сообщают о монохромных снах.",source:"Murzyn (2008), Consciousness and Cognition"},{id:5,type:"Символ",text:"Вода во сне часто символизирует эмоции, подсознание и внутренние переживания.",expandable:!0,title:"Вода во сне",fullText:`Вода — один из универсальных архетипических символов в мировой культуре и в снах. В юнгианском анализе вода представляет бессознательное — его глубину, силу и непредсказуемость. Характер воды в сне говорит об эмоциональном состоянии сновидца.

Спокойное море или озеро — гармония, внутренний покой. Бурное море, наводнение — захлёстывающие эмоции, потеря контроля. Грязная мутная вода — непроработанные чувства, замешательство. Чистый ручей — свежие идеи, движение вперёд.

Во многих мифологиях вода символизирует переход между мирами: река Стикс в греческой мифологии, "воды хаоса" в шумерском эпосе. Если вам снится, что вы тонете — это не предсказание гибели, а сигнал о том, что вы чувствуете себя захлёстнутым ситуацией в жизни.

Подсказка: запишите, каким было состояние воды в вашем сне — это ключ к пониманию своего эмоционального фона.`,source:'Jung, "The Archetypes and the Collective Unconscious" (1959)'},{id:6,type:"Факт",text:"Люди могут учиться осознанным сновидениям — контролю над своими снами.",expandable:!0,title:"Осознанные сновидения",fullText:`Осознанное сновидение (lucid dream) — это состояние, когда вы понимаете внутри сна, что спите, и можете влиять на происходящее. Первые научные доказательства его существования получил Стивен Лаберж в Стэнфорде в 1980-х, используя согласованные движения глаз как сигнал из сна.

По данным исследований, около 55% людей хотя бы раз в жизни переживали осознанное сновидение. Регулярно осознанно сновидят около 23%.

Есть несколько техник для освоения этого навыка:
• MILD (Мнемонически индуцированные осознанные сны) — намерение перед сном.
• WILD (Пробуждение в сновидение) — переход из бодрствования напрямую в сон с сохранением сознания.
• Дневник снов — осознание паттернов и "триггеров" сновидений.
• Reality checks — проверка реальности в течение дня (пальцы, текст).

Осознанные сны используются для преодоления ночных кошмаров, творческой практики и даже репетиции навыков.`,source:'LaBerge, "Lucid Dreaming" (1985)'},{id:7,type:"Миф",text:"Миф: если умрёшь во сне, умрёшь в реальности.",expandable:!0,title:"Смерть во сне",fullText:'Этот миф никак не подтверждён научно. Многие люди видят сны о собственной смерти и просыпаются совершенно здоровыми. С точки зрения психологии такой сон чаще символизирует конец одного жизненного этапа и начало нового — не физическую гибель. Архетип "смерти и возрождения" — один из ключевых в юнгианском анализе снов.',source:'Calvin Hall, "The Meaning of Dreams" (1966)'},{id:8,type:"Символ",text:"Падение во сне обычно отражает чувство потери контроля в жизни.",expandable:!0,title:"Падение во сне",fullText:`Сон о падении — один из самых распространённых и пугающих. Часто он сопровождается резким толчком тела при пробуждении — это явление называется гипнагогический миоклонус (sleep start). Это физиологически нормальная реакция нервной системы при переходе ко сну.

С психологической точки зрения, падение во сне связано с тревогой и чувством потери почвы под ногами. Оно может возникать в периоды нестабильности: смена работы, отношений, переезд, экзамены.

Разные варианты падения несут разные смыслы:
• Падение с высоты — страх неудачи, завышенные требования к себе.
• Полёт, переходящий в падение — утрата контроля после периода уверенности.
• Падение в бездну без дна — экзистенциальная тревога, неопределённость будущего.

Если такие сны повторяются — это сигнал: стоит разобраться, в какой сфере жизни вы чувствуете нестабильность.`,source:'Hartmann, "The Dream Always Makes New Connections" (1995)'},{id:9,type:"Факт",text:"Во время REM-сна мозг активен почти как в бодрствующем состоянии.",expandable:!0,title:"Мозг во время REM-сна",fullText:`REM (Rapid Eye Movement) — фаза быстрого сна, во время которой происходит большинство ярких сновидений. Название она получила из-за быстрых движений глаз под закрытыми веками.

Во время REM активность мозга по данным ЭЭГ почти неотличима от бодрствования. Активны зоны, отвечающие за эмоции (амигдала), зрительную обработку и моторное планирование. При этом префронтальная кора — отвечающая за критическое мышление — работает значительно слабее. Именно поэтому во снах мы принимаем абсурдное за реальное.

Мышцы тела во время REM парализованы (атония) — защитный механизм, чтобы мы не воспроизводили движения из сна. Нарушение этого механизма называется REM sleep behavior disorder — при нём люди буквально "разыгрывают" сны.

REM-сон критически важен для памяти и обучения: именно в нём мозг консолидирует эмоциональные воспоминания и интегрирует новую информацию.`,source:'Walker, "Why We Sleep" (2017)'},{id:10,type:"Символ",text:'Дом во сне часто отражает ваше внутреннее "Я" и чувство безопасности.',expandable:!0,title:"Дом во сне",fullText:"В символике снов дом — это образ психики. Разные комнаты соответствуют разным аспектам личности: подвал — подсознание и вытесненные страхи, чердак — память и прошлое, спальня — интимная жизнь. Незнакомые комнаты в знакомом доме символизируют нераскрытые потенциалы или стороны личности, которые ещё не исследованы.",source:'Freud, "Interpretation of Dreams" (1900)'},{id:11,type:"Факт",text:"Люди чаще запоминают кошмары из-за сильных эмоций.",expandable:!0,title:"Почему кошмары запоминаются",fullText:`Кошмары запоминаются лучше приятных снов по той же причине, по которой страх эффективнее радости фиксируется в памяти — это эволюционный механизм выживания. Амигдала (центр эмоциональной обработки) при кошмарах работает на пике активности, выбрасывая норэпинефрин и активируя систему "бей или беги".

Резкое пробуждение в середине кошмара также способствует запоминанию: мозг не успевает "смыть" образы, как при мягком выходе из сна.

Научно доказано: частые кошмары могут быть признаком стресса, тревожного расстройства или ПТСР. При этом работа с содержанием кошмаров через технику Image Rehearsal Therapy (IRT) — намеренное переписывание финала кошмара в бодрствовании — значительно снижает их частоту.

Интересный факт: творческие люди сообщают о кошмарах чаще, чем в среднем по популяции — возможно, из-за более богатого воображения и высокой эмоциональной чувствительности.`,source:'Levin & Nielsen, "Disturbed Dreaming, Posttraumatic Stress" (2007)'},{id:12,type:"Символ",text:"Животные во сне символизируют инстинкты и скрытые стороны личности.",expandable:!0,title:"Животные во сне",fullText:`В аналитической психологии Юнга животные в снах — это проявления "Тени" или инстинктивной части психики, которая не получает выражения в повседневной жизни. Каждое животное несёт свою символику, укоренённую в мифологии и архетипах.

Волк — агрессия, дикая природа, но и верность стае. Змея — мудрость, трансформация, скрытая угроза или исцеление (символ медицины — кадуцей). Лев — сила, власть, уверенность в себе. Бабочка — трансформация, легкость, краткосрочность. Паук — творчество (создаёт сеть), но и манипуляция, ловушки.

Если вас преследует животное во сне — это не обязательно угроза извне. Это может быть та часть вас самих, которую вы отвергаете или боитесь принять. Подружиться с "хищником" во сне — архетипический образ интеграции Тени.

Анализируя сон с животным, спросите себя: что это существо для меня значит? Какое качество оно воплощает — и как оно выражается (или подавляется) в моей жизни?`,source:'Jung, "Man and His Symbols" (1964)'}]),v=()=>{U(()=>{if(m.value.length){const e=m.value.map(a=>{var t;return((t=a==null?void 0:a.$el)==null?void 0:t.offsetHeight)||224});b.value=Math.max(224,...e)}})},A=e=>{i.value=e,v(),requestAnimationFrame(()=>e.slideTo(e.activeIndex,0,!1))},M=()=>{try{const e=document.querySelector("main section.account-block"),a=e==null?void 0:e.querySelector("article"),t=a==null?void 0:a.getBoundingClientRect().width;t&&t>0&&(f.value=Math.round(t),w.value=Math.max(0,Math.round((window.innerWidth-f.value)/2)))}catch{}},B=()=>{v(),i.value&&(i.value.update(),i.value.slideTo(i.value.activeIndex,0,!1))};return N(()=>{v(),M(),window.addEventListener("resize",v),window.addEventListener("resize",M),window.addEventListener("resize",B)}),V(()=>{window.removeEventListener("resize",v),window.removeEventListener("resize",M),window.removeEventListener("resize",B)}),(e,a)=>(c(),p("section",Y,[R(S(Q),{modules:I,"slides-per-view":"auto",spaceBetween:re,centeredSlides:!0,centeredSlidesBounds:!0,autoplay:z,keyboard:{enabled:!0},a11y:{enabled:!0},observer:!0,"observe-parents":!0,"watch-overflow":!0,speed:650,onInit:A,class:"w-screen",style:L({height:b.value+"px",paddingLeft:w.value+"px",paddingRight:w.value+"px"})},{default:_(()=>[(c(!0),p(q,null,O(W.value,(t,l)=>(c(),$(S(j),{key:t.id,ref_for:!0,ref_key:"cardRefs",ref:m,class:k(["card-slide rounded-xl overflow-hidden bg-gradient-to-br from-[#6A4DFF] to-[#9A3CFF] text-white p-8 flex flex-col justify-between will-change-transform w-auto flex-shrink-0",{"card-expandable":t.expandable}]),style:L({height:b.value+"px",width:f.value+"px"}),onClick:r=>t.expandable?H(t):null},{default:_(()=>[n("div",Z,[n("span",{class:k(["fact-badge",`fact-badge--${C(t.type)}`])},x(T(t.type)),3),t.expandable?(c(),p("span",ee,[...a[1]||(a[1]=[n("svg",{width:"16",height:"16",viewBox:"0 0 24 24",fill:"none",stroke:"currentColor","stroke-width":"2.5","stroke-linecap":"round"},[n("polyline",{points:"15 3 21 3 21 9"}),n("polyline",{points:"9 21 3 21 3 15"}),n("line",{x1:"21",y1:"3",x2:"14",y2:"10"}),n("line",{x1:"3",y1:"21",x2:"10",y2:"14"})],-1)])])):h("",!0)]),n("p",te,x(t.text),1)]),_:2},1032,["class","style","onClick"]))),128))]),_:1},8,["style"]),R(J,{name:"card-expand"},{default:_(()=>[s.value?(c(),p("div",{key:0,class:"card-overlay",onClick:D(g,["self"])},[n("div",{class:"card-overlay-sheet",onClick:a[0]||(a[0]=D(()=>{},["stop"]))},[a[2]||(a[2]=n("div",{class:"card-overlay-handle"},null,-1)),n("div",ae,[n("span",{class:k(["fact-badge",`fact-badge--${C(s.value.type)}`])},x(T(s.value.type)),3),n("button",{class:"card-overlay-close",onClick:g,"aria-label":"Закрыть"},"✕")]),s.value.title?(c(),p("div",ne,x(s.value.title),1)):h("",!0),n("div",se,x(s.value.fullText||s.value.text),1),s.value.source?(c(),p("div",le," Источник: "+x(s.value.source),1)):h("",!0)])])):h("",!0)]),_:1})]))}}),pe=X(ie,[["__scopeId","data-v-8e34e657"]]);export{pe as default};
